import React, {useState} from "react";
import classes from './ProfileInfo.module.css';
import Preloader from "../../Common/Preloader/Preloader";
import yesLogo from '../../img/Yes.png';
import noLogo from '../../img/No.png';
import ProfileStatusWithHooks from "./ProfileStatusWithHooks";
import userDefaultPhoto from "../../img/user.png";
import ProfileDataForm from "./ProfileDataForm";



const ProfileInfo = ({profile,
                         status,
                         updateUserStatus,
                         isOwner,
                         savePhoto,
                     saveProfile}) => {
    //Т.К. изначально в редьюсере профайл null
    //то пишем условие !props.profile - если в пропсе ничего нет
    //это аналог (props.profile==null || props.profile)
    //если пропсы равны нулл или (||-это или андефайдет)
    //! - это отрицание
    let [editMode, setEditMode] = useState(false);


    if (!profile) {
        return <Preloader/>
    }
    const onMainPhotoSelected = (e) => {
        if (e.target.files.length) {
            savePhoto(e.target.files[0])
        }
    }

    const onSubmit = (formData) => {
        saveProfile(formData);
        
    }

    return <div className={classes.content}>
        <div className={classes.topImage}>
            <img src='https://pbs.twimg.com/profile_banners/2887963515/1502618076/1500x500'
                 alt='Верхний баннер профиля'/>
        </div>
        <div>
            <div className={classes.avatar}>
                <img src='https://sun9-37.userapi.com/c830400/v830400294/3874c/biJ545FuTIE.jpg?ava=1' alt='Аватар'/>
                {/*<img src={profile.photos.large || userDefaultPhoto} alt='Аватар'/>*/}
                <ProfileStatusWithHooks status={status} updateUserStatus={updateUserStatus}/>
                <div className={classes.avatar}>
                    <img src={profile.photos.small ? profile.photos.small : userDefaultPhoto}
                         alt='Аватар'/>
                    {isOwner && <input type={'file'} onChange={onMainPhotoSelected}/>}
                </div>
            </div>
            {editMode
                ? <ProfileDataForm initialValues={profile} profile={profile} onSubmit={onSubmit}/>
                : <ProfileData profile={profile} isOwner={isOwner} goToEditMode={() => {
                    setEditMode(true)
                }}/>}
        </div>
    </div>
}

const ProfileData = ({profile, isOwner, goToEditMode}) => {
    return <div>
        {isOwner && <div>
            <button onClick={goToEditMode}>Edit</button>
        </div>}
        <ul className={classes.profiletext}>
            <li><b>Полное имя:</b> {profile.fullName}</li>
            <li><b>О себе:</b> {profile.aboutMe}</li>
            <li><b>Мои контакты:</b></li>
            <div>
                <b>Contacts</b>: {Object.keys(profile.contacts).map(key => {
                return <Contact key={key} contactTitle={key} contactValue={profile.contacts[key]}/>
            })}
            </div>
            <li><b>В поиске работы:</b>
                <img src={profile.lookingForAJob ? yesLogo : noLogo}
                     alt={'AnswerLogo'}/></li>
            <li>Описание поиска работы: {profile.lookingForAJobDescription}</li>
        </ul>
    </div>

}


const Contact = ({contactTitle, contactValue}) => {
    return <div><b>{contactTitle}</b>:{contactValue} </div>
}

export default ProfileInfo;

/*{условие (да или нет) ? значение 1 (да) : значение 2 (нет)}*/

